// src/components/Common/managerCard.js
import React from "react";

export default function ManagerCard({ manager, onClick }) {
  return (
    <div className="manager-card-component" onClick={onClick} style={{ cursor: onClick ? 'pointer' : 'default' }}>
      <div className="manager-card-inner">
        <div className="manager-card-image">
          <img src={manager.profileImage || manager.avatar} alt={manager.name} />
          <div className="manager-status-badge">
            <span className={`status-dot ${manager.status === 'active' ? 'active' : 'inactive'}`}></span>
          </div>
        </div>
        
        <div className="manager-card-info">
          <h3 className="manager-name">{manager.name}</h3>
          <p className="manager-role">👔 {manager.role || "Directeur"}</p>
          
          <div className="manager-details">
            <div className="manager-detail-item">
              <span className="detail-icon">📍</span>
              <span className="detail-text">{manager.location || "Non spécifié"}</span>
            </div>
            <div className="manager-detail-item">
              <span className="detail-icon">⭐</span>
              <span className="detail-text">{manager.rating || "4.8"} / 5</span>
            </div>
            <div className="manager-detail-item">
              <span className="detail-icon">👥</span>
              <span className="detail-text">{manager.employees || "0"} employés</span>
            </div>
            <div className="manager-detail-item">
              <span className="detail-icon">🏪</span>
              <span className="detail-text">{manager.restaurantCount || "1"} restaurant(s)</span>
            </div>
          </div>
          
          <div className="manager-experience">
            <span className="experience-icon">📅</span>
            <span className="experience-text">{manager.experience || "5 ans d'expérience"}</span>
          </div>
          
          <div className="manager-skills">
            {manager.skills && manager.skills.slice(0, 3).map((skill, index) => (
              <span key={index} className="skill-tag-mini">{skill}</span>
            ))}
            {manager.skills && manager.skills.length > 3 && (
              <span className="skill-tag-mini more">+{manager.skills.length - 3}</span>
            )}
          </div>
        </div>
        
        <div className="manager-card-footer">
          <button className="manager-contact-btn">
            📧 Contacter
          </button>
          <button className="manager-profile-btn">
            Voir profil
          </button>
        </div>
      </div>
      
      <style jsx>{`
        .manager-card-component {
          background: linear-gradient(135deg, rgba(255,255,255,0.1), rgba(255,255,255,0.05));
          backdrop-filter: blur(10px);
          border-radius: 20px;
          overflow: hidden;
          transition: all 0.3s ease;
          border: 1px solid rgba(34, 197, 94, 0.3);
          margin: 10px;
        }
        
        .manager-card-component:hover {
          transform: translateY(-5px);
          box-shadow: 0 15px 35px rgba(0,0,0,0.3);
          border-color: rgba(34, 197, 94, 0.6);
        }
        
        .manager-card-inner {
          padding: 20px;
        }
        
        .manager-card-image {
          position: relative;
          display: flex;
          justify-content: center;
          margin-bottom: 15px;
        }
        
        .manager-card-image img {
          width: 100px;
          height: 100px;
          border-radius: 50%;
          object-fit: cover;
          border: 3px solid #22c55e;
          box-shadow: 0 5px 15px rgba(0,0,0,0.3);
        }
        
        .manager-status-badge {
          position: absolute;
          bottom: 5px;
          right: 35%;
          background: rgba(0,0,0,0.6);
          border-radius: 50%;
          width: 28px;
          height: 28px;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        
        .status-dot {
          width: 12px;
          height: 12px;
          border-radius: 50%;
          display: inline-block;
        }
        
        .status-dot.active {
          background: #22c55e;
          box-shadow: 0 0 8px #22c55e;
        }
        
        .status-dot.inactive {
          background: #ef4444;
          box-shadow: 0 0 8px #ef4444;
        }
        
        .manager-card-info {
          text-align: center;
        }
        
        .manager-name {
          font-size: 1.3rem;
          font-weight: bold;
          color: white;
          margin-bottom: 5px;
        }
        
        .manager-role {
          color: #22c55e;
          font-size: 0.8rem;
          margin-bottom: 15px;
        }
        
        .manager-details {
          background: rgba(255,255,255,0.08);
          border-radius: 15px;
          padding: 10px;
          margin-bottom: 12px;
        }
        
        .manager-detail-item {
          display: flex;
          align-items: center;
          gap: 8px;
          padding: 5px 0;
          color: rgba(255,255,255,0.7);
          font-size: 0.8rem;
        }
        
        .detail-icon {
          width: 25px;
          font-size: 1rem;
        }
        
        .detail-text {
          flex: 1;
          text-align: left;
        }
        
        .manager-experience {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 8px;
          padding: 8px;
          background: rgba(34,197,94,0.15);
          border-radius: 12px;
          margin-bottom: 12px;
          color: #22c55e;
          font-size: 0.8rem;
        }
        
        .manager-skills {
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          gap: 5px;
          margin-bottom: 15px;
        }
        
        .skill-tag-mini {
          background: rgba(34,197,94,0.2);
          border: 1px solid rgba(34,197,94,0.3);
          border-radius: 12px;
          padding: 3px 8px;
          font-size: 0.7rem;
          color: #4ade80;
        }
        
        .skill-tag-mini.more {
          background: rgba(255,255,255,0.1);
          color: rgba(255,255,255,0.6);
        }
        
        .manager-card-footer {
          display: flex;
          gap: 10px;
          margin-top: 10px;
        }
        
        .manager-contact-btn {
          flex: 1;
          background: linear-gradient(135deg, #22c55e, #15803d);
          border: none;
          padding: 8px;
          border-radius: 12px;
          color: white;
          font-size: 0.75rem;
          font-weight: bold;
          cursor: pointer;
          transition: all 0.3s;
        }
        
        .manager-contact-btn:hover {
          transform: scale(1.02);
          box-shadow: 0 0 12px rgba(34,197,94,0.4);
        }
        
        .manager-profile-btn {
          flex: 1;
          background: rgba(255,255,255,0.1);
          border: 1px solid rgba(34,197,94,0.3);
          padding: 8px;
          border-radius: 12px;
          color: white;
          font-size: 0.75rem;
          font-weight: bold;
          cursor: pointer;
          transition: all 0.3s;
        }
        
        .manager-profile-btn:hover {
          background: rgba(255,255,255,0.2);
          border-color: #22c55e;
        }
        
        @media (max-width: 480px) {
          .manager-card-inner {
            padding: 15px;
          }
          
          .manager-card-image img {
            width: 80px;
            height: 80px;
          }
          
          .manager-name {
            font-size: 1.1rem;
          }
          
          .manager-detail-item {
            font-size: 0.7rem;
          }
        }
      `}</style>
    </div>
  );
}
